export const WEATHER_ICONS: Record<string, string> = {
  Sunny: '☀️',
  Cloudy: '☁️',
  Rainy: '🌧️',
  Snowy: '❄️',
  'Partly Cloudy': '⛅',
  Default: '🌡️',
};

export const UNIT_SYMBOLS: Record<string, string> = {
  C: '°C',
  F: '°F',
};

export const WIND_SPEED_UNITS: Record<string, string> = {
  metric: 'km/h',
  imperial: 'mph',
};

export const CONDITION_DESCRIPTIONS: Record<string, string> = {
  Sunny: 'Clear and sunny',
  Cloudy: 'Overcast clouds',
  Rainy: 'Precipitation and rain',
  Snowy: 'Snowfall',
  'Partly Cloudy': 'Mix of sun and clouds',
  Default: 'Weather condition unknown',
};

export const DEFAULT_UNIT = 'C';
export const MAX_FORECAST_DAYS = 5;

export const getIconForCondition = (condition: string): string => {
  return WEATHER_ICONS[condition] || WEATHER_ICONS.Default;
};

export const getDescriptionForCondition = (condition: string): string => {
  return CONDITION_DESCRIPTIONS[condition] || CONDITION_DESCRIPTIONS.Default;
};

