// Path: /virtual/hooks.ts
import type { Props, HookReturn } from '/virtual/types';
import * as constants from '/virtual/constants';
// hooks.ts — state, handlers, data transformations
import { useState, useEffect, useMemo, useCallback, useRef } from 'react';

const CONDITION_ICONS: Record<string, string> = {
  sunny: '☀️',
  rainy: '🌧️',
  cloudy: '☁️',
  snowy: '❄️',
};

export function useComponent(props: Props): HookReturn {
  const { city, temperature, condition, humidity, windSpeed, unit } = props;

  const displayUnit = useMemo(() => unit || 'C', [unit]);

  const formattedTemp = useMemo(() => {
    return `${Math.round(temperature)}°${displayUnit}`;
  }, [temperature, displayUnit]);

  const formattedWind = useMemo(() => {
    const suffix = displayUnit === 'F' ? 'mph' : 'km/h';
    return `${windSpeed} ${suffix}`;
  }, [windSpeed, displayUnit]);

  const formattedHumidity = useMemo(() => {
    return `${humidity}%`;
  }, [humidity]);

  const conditionIcon = useMemo(() => {
    return CONDITION_ICONS[condition.toLowerCase()] || '🌡️';
  }, [condition]);

  const ariaLabel = useMemo(() => {
    return `Weather in ${city}: ${condition}, ${formattedTemp}. Humidity ${formattedHumidity}, Wind speed ${formattedWind}.`;
  }, [city, condition, formattedTemp, formattedHumidity, formattedWind]);

  return {
    formattedTemp,
    formattedWind,
    formattedHumidity,
    displayUnit,
    conditionIcon,
    ariaLabel,
  };
}


