import React from 'react';
import { Stack, Heading, Text, Divider } from '@ggui-ai/design/primitives';
import { WeatherHeaderProps } from '/virtual/types';

/**
 * WeatherHeader displays the location, condition, and primary temperature reading.
 */
export const WeatherHeader: React.FC<WeatherHeaderProps> = ({
  city,
  temperature,
  condition,
  unit,
}) => {
  return (
    <Stack gap={16}>
      <Stack direction="horizontal" justify="between" align="center">
        {/* Location Group */}
        <Stack gap={4}>
          <Heading level={3}>{city}</Heading>
          <Text 
            variant="bodySmall" 
            color="var(--ggui-color-onSurfaceVariant)"
          >
            {condition}
          </Text>
        </Stack>

        {/* Temperature Group - Wrapped in a div for accessibility and custom layout */}
        <div aria-label={`${temperature} degrees ${unit}`}>
          <Stack direction="horizontal" align="start" gap={4}>
            <Text 
              weight="bold"
              style={{ 
                fontSize: '3rem', 
                lineHeight: 'var(--ggui-lineHeight-none, 1)' 
              }}
            >
              {temperature}
            </Text>
            <div style={{ marginTop: 'var(--ggui-spacing-2, 8px)' }}>
              <Text variant="bodyLarge">
                °{unit}
              </Text>
            </div>
          </Stack>
        </div>
      </Stack>

      {/* Separator to details section */}
      <Divider margin={0} />
    </Stack>
  );
};


