import React from 'react';
import { Box, Divider, Stack, Text } from '@ggui-ai/design/primitives';
import { ForecastStripProps, ForecastDay } from '/virtual/types';

/**
 * Individual forecast item for a single day.
 */
const ForecastItem: React.FC<{ day: ForecastDay; unit: string }> = ({ day }) => {
  return (
    <Stack align="center" gap={4}>
      <Text
        variant="bodySmall"
        weight="bold"
        color="var(--ggui-color-onSurfaceVariant)"
      >
        {day.day}
      </Text>
      <Text style={{ fontSize: '1.5rem', lineHeight: 1 }}>
        {day.icon}
      </Text>
      <Stack direction="horizontal" gap={2} justify="center">
        <Text variant="bodySmall" color="var(--ggui-color-onSurface)">
          {day.high}°
        </Text>
        <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
          / {day.low}°
        </Text>
      </Stack>
    </Stack>
  );
};

/**
 * ForecastStrip component displaying a 5-day weather forecast.
 */
export const ForecastStrip: React.FC<ForecastStripProps> = ({ forecast, unit }) => {
  if (!forecast || forecast.length === 0) {
    return <Box />;
  }

  return (
    <Box style={{ paddingTop: 'var(--ggui-spacing-4)' }}>
      <Divider margin={16} />
      <Box paddingY="var(--ggui-spacing-2)">
        <Stack
          direction="horizontal"
          gap="var(--ggui-spacing-4)"
          justify="between"
          align="center"
          style={{ overflowX: 'auto', paddingBottom: 'var(--ggui-spacing-2)' }}
        >
          {forecast.map((day, index) => (
            <ForecastItem key={`${day.day}-${index}`} day={day} unit={unit} />
          ))}
        </Stack>
      </Box>
    </Box>
  );
};

