export type SurveyFormData = {
  name: string;
  email: string;
  satisfaction: string;
  features: string[];
  comments: string;
};

export type SurveyErrors = {
  name?: string;
  email?: string;
  satisfaction?: string;
  features?: string[];
  comments?: string;
};

export interface SurveyProps {
  featureOptions: string[];
  satisfactionLabels: string[];
  onSubmit: (data: SurveyFormData) => void;
}

export type StepId = 'personal' | 'satisfaction' | 'features' | 'comments' | 'review';

export interface UseSurveyReturn {
  activeStepIndex: number;
  currentStepId: StepId;
  formData: SurveyFormData;
  errors: SurveyErrors;
  isStepValid: boolean;
  totalSteps: number;
  handleNext: () => void;
  handleBack: () => void;
  handleSubmit: () => void;
  updateField: <K extends keyof SurveyFormData>(field: K, value: SurveyFormData[K]) => void;
}

export interface StepProgressProps {
  currentStep: number;
  totalSteps: number;
}

export interface PersonalInfoStepProps {
  data: Pick<SurveyFormData, 'name' | 'email'>;
  errors: SurveyErrors;
  onChange: UseSurveyReturn['updateField'];
}

export interface SatisfactionStepProps {
  labels: string[];
  value: string;
  onChange: (val: string) => void;
}

export interface FeaturesStepProps {
  options: string[];
