import { SurveyFormData, StepId } from '/virtual/types';

export const INITIAL_FORM_DATA: SurveyFormData = {
  name: '',
  email: '',
  satisfaction: '',
  features: [],
  comments: '',
};

export const STEPS: Array<{ id: StepId; label: string; fields: Array<keyof SurveyFormData> }> = [
  {
    id: 'personal',
    label: 'Personal Info',
    fields: ['name', 'email'],
  },
  {
    id: 'satisfaction',
    label: 'Satisfaction',
    fields: ['satisfaction'],
  },
  {
    id: 'features',
    label: 'Favorite Features',
    fields: ['features'],
  },
  {
    id: 'comments',
    label: 'Comments',
    fields: ['comments'],
  },
  {
    id: 'review',
    label: 'Review',
    fields: [],
  },
];

export const MAX_COMMENT_LENGTH = 500;
export const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
export const TOTAL_STEPS = STEPS.length;

// --- hooks.ts ---
// Path: /virtual/hooks.ts
import type { Props, HookReturn } from '/virtual/types';
import * as constants from '/virtual/constants';
// hooks.ts — state, handlers, data transformations
import { useState, useEffect, useMemo, useCallback } from 'react';

// ── Action Handlers (from actionsSpec) ──────────────────
//   props.actions: {"submit":{"label":"Submit Survey","description":"Called with all collected answers as a structured object","example":{"name":"John","email":"john@example.com","satisfaction":4,"features":["API Integration","Mobile App"],"comments":"Great product!"}}}

const STEPS: StepId[] = ['personal', 'satisfaction', 'features', 'comments', 'review'];

export function useComponent(props: Props): HookReturn {
  const [activeStepIndex, setActiveStepIndex] = useState(0);
  const [formData, setFormData] = useState<SurveyFormData>({
    name: '',
    email: '',
    satisfaction: '',
    features: [],
    comments: '',
  });

  const [errors, setErrors] = useState<SurveyErrors>({});

  // Internal validation effect
  useEffect(() => {
    const newErrors: SurveyErrors = {};
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

    if (!formData.name.trim()) {
      newErrors.name = 'Name is required';
    }

    if (!formData.email.trim()) {
      newErrors.email = 'Email is required';
    } else if (!emailRegex.test(formData.email.trim())) {
      newErrors.email = 'Invalid email format';
    }

    if (!formData.satisfaction) {
      newErrors.satisfaction = 'Satisfaction level is required';
    }

    if (formData.comments.length > 500) {
      newErrors.comments = 'Comments must be 500 characters or less';
    }

    setErrors(newErrors);
  }, [formData]);

  const updateField = useCallback(<K extends keyof SurveyFormData>(field: K, value: SurveyFormData[K]) => {
    setFormData(prev => ({
      ...prev,
      [field]: value
    }));
  }, []);

  const isStepValid = useMemo(() => {
    const stepId = STEPS[activeStepIndex];
    switch (stepId) {
      case 'personal':
        return !!formData.name.trim() && !!formData.email.trim() && !errors.name && !errors.email;
      case 'satisfaction':
        return !!formData.satisfaction && !errors.satisfaction;
      case 'features':
        return true;
      case 'comments':
        return formData.comments.length <= 500 && !errors.comments;
      case 'review':
        return true;
      default:
        return false;
    }
  }, [activeStepIndex, formData, errors]);

  const handleNext = useCallback(() => {
    if (isStepValid && activeStepIndex < STEPS.length - 1) {
      setActiveStepIndex(prev => prev + 1);
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }
  }, [isStepValid, activeStepIndex]);

  const handleBack = useCallback(() => {
    if (activeStepIndex > 0) {
      setActiveStepIndex(prev => prev - 1);
      window.scrollTo({ top: 0, behavior: 'smooth' });
    }
  }, [activeStepIndex]);

  const handleSubmit = useCallback(() => {
    props.onSubmit(formData);
  }, [props.onSubmit, formData]);

  const currentStepId = STEPS[activeStepIndex];
  const totalSteps = STEPS.length;

  return {
    activeStepIndex,
    currentStepId,
    formData,
    errors,
    isStepValid,
    totalSteps,
    handleNext,
    handleBack,
    handleSubmit,
    updateField,
  };
}


