import React from 'react';
import { Stack, Text, Progress, Box } from '@ggui-ai/design/primitives';
import { StepProgressProps } from '/virtual/types';

export const StepProgress: React.FC<StepProgressProps> = ({
  currentStep,
  totalSteps,
}) => {
  // Calculate the completion percentage based on current step index
  const percentage = (currentStep / totalSteps) * 100;

  return (
    <Box margin="0 0 var(--ggui-spacing-4) 0">
      <Stack direction="vertical" gap={8} align="stretch">
        <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
          Step {currentStep} of {totalSteps}
        </Text>
        <Progress value={percentage} max={100} size="sm" />
      </Stack>
    </Box>
  );
};


