import React from 'react';
import { Stack, Heading, Text, RadioGroup } from '@ggui-ai/design/primitives';
import { SatisfactionStepProps } from '/virtual/types';

/**
 * SatisfactionStep - Step 2 of the survey.
 * Provides a radio group for selecting satisfaction level based on custom labels.
 */
export const SatisfactionStep: React.FC<SatisfactionStepProps> = ({
  labels,
  value,
  onChange,
}) => {
  // Map semantic labels to RadioGroup options
  const radioOptions = labels.map((label) => ({
    value: label,
    label: label,
  }));

  return (
    <Stack gap="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-2)">
        <Heading level={3} color="var(--ggui-color-onSurface)">
          Overall Satisfaction
        </Heading>
        <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
          Please select the rating that best describes your experience.
        </Text>
      </Stack>

      <div style={{ width: '100%' }}>
        <RadioGroup
          label="Satisfaction Level"
          value={value}
          onChange={onChange}
          options={radioOptions}
        />
      </div>
    </Stack>
  );
};

// --- components/FeaturesStep.tsx ---
// Path: /virtual/components/FeaturesStep.tsx
import React from 'react';
import { Stack, Checkbox, Heading, Text } from '@ggui-ai/design/primitives';
import { FeaturesStepProps } from '/virtual/types';

export const FeaturesStep: React.FC<FeaturesStepProps> = ({
  options,
  selectedFeatures,
  onChange,
}) => {
  const handleToggle = (option: string) => {
    const isSelected = selectedFeatures.includes(option);
    const updatedFeatures = isSelected
      ? selectedFeatures.filter((f) => f !== option)
      : [...selectedFeatures, option];
    onChange(updatedFeatures);
  };

  return (
    <Stack gap="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-2)">
        <Heading level={3}>Feature Interests</Heading>
        <Text variant="body" color="var(--ggui-color-onSurfaceVariant, #52525b)">
          Select all the features you are interested in trying or learning more about:
        </Text>
      </Stack>

      <Stack gap="var(--ggui-spacing-3)">
        {options.map((option) => (
          <Checkbox
            key={option}
            label={option}
            checked={selectedFeatures.includes(option)}
            onChange={() => handleToggle(option)}
            // @ts-ignore - value prop requested by instructions
            value={option}
          />
        ))}
      </Stack>
    </Stack>
  );
};

