// Path: /virtual/components/ReviewStep.tsx
import React from 'react';
import { Stack, Box, Text, Heading, Divider } from '@ggui-ai/design/primitives';
import { Tag } from '@ggui-ai/design/components';
import { ReviewStepProps } from '/virtual/types';

export const ReviewStep: React.FC<ReviewStepProps> = ({ data, labels }) => {
  // data.satisfaction usually arrives as an index string from RadioGroup
  const satisfactionIndex = parseInt(data.satisfaction, 10);
  const satisfactionDisplay = !isNaN(satisfactionIndex) && labels[satisfactionIndex] 
    ? labels[satisfactionIndex] 
    : data.satisfaction;

  return (
    <Stack gap={24}>
