import type { SurveyProps, UseSurveyReturn } from '/virtual/types';
// components/index.tsx — main component composing sub-components
import React from 'react';
import { Container, Card, Stack, Box, Divider, Heading } from '@ggui-ai/design/primitives';
import {
  StepProgress,
  PersonalInfoStep,
  SatisfactionStep,
  FeaturesStep,
  CommentsStep,
  ReviewStep,
  StepNavigation,
} from '/virtual/components';

export function Component(props: SurveyProps & UseSurveyReturn) {
  const {
    activeStepIndex,
    currentStepId,
    formData,
    errors,
    isStepValid,
    totalSteps,
    handleNext,
    handleBack,
    handleSubmit,
    updateField,
    featureOptions,
    satisfactionLabels,
  } = props;

  const renderStepContent = () => {
    switch (currentStepId) {
      case 'personal':
        return (
          <PersonalInfoStep
            data={{ name: formData.name, email: formData.email }}
            errors={errors}
            onChange={updateField}
          />
        );
      case 'satisfaction':
        return (
          <SatisfactionStep
            labels={satisfactionLabels}
            value={formData.satisfaction}
            onChange={(val) => updateField('satisfaction', val)}
          />
        );
      case 'features':
        return (
          <FeaturesStep
            options={featureOptions}
            selectedFeatures={formData.features}
            onChange={(features) => updateField('features', features)}
          />
        );
      case 'comments':
        return (
          <CommentsStep
            value={formData.comments}
            onChange={(val) => updateField('comments', val)}
            maxLength={500}
          />
        );
      case 'review':
        return <ReviewStep data={formData} labels={satisfactionLabels} />;
      default:
        return null;
    }
  };

  return (
    <Container maxWidth="600px" padding="var(--ggui-spacing-4)">
      <Card shadow="lg" padding="var(--ggui-spacing-6)" radius="xl">
        <Stack gap="var(--ggui-spacing-6)">
          <Stack gap="var(--ggui-spacing-4)">
            <Heading level={2} align="center">Product Feedback Survey</Heading>
            <StepProgress currentStep={activeStepIndex} totalSteps={totalSteps} />
          </Stack>

          <Divider margin="var(--ggui-spacing-2)" />

          <Box style={{ minHeight: '340px' }}>
            {renderStepContent()}
          </Box>

          <Divider margin="var(--ggui-spacing-2)" />

          <StepNavigation
            activeStepIndex={activeStepIndex}
            totalSteps={totalSteps}
            isNextDisabled={!isStepValid}
            onBack={handleBack}
            onNext={handleNext}
            onSubmit={handleSubmit}
          />
        </Stack>
      </Card>
    </Container>
  );
}


