// --- hooks.ts ---
// Path: /virtual/hooks.ts
import type { Props, HookReturn } from '/virtual/types';
import * as constants from '/virtual/constants';
// hooks.ts — state, handlers, data transformations
import { useState, useEffect, useMemo, useCallback } from 'react';

// ── Action Handlers (from actionsSpec) ──────────────────
//   props.actions: {"taskUpdate":{"label":"Task Updated","description":"Called when a task is moved, edited, or created. Payload: { action, taskId, data }","example":{"action":"move","taskId":"1","data":{"column":"in-progress"}}}}

export function useComponent(props: Props): HookReturn {
  const { tasks, columns, onTaskUpdate } = props;

  const [localTasks, setLocalTasks] = useState<Task[]>(tasks);

  useEffect(() => {
    setLocalTasks(tasks);
  }, [tasks]);

  const stats = useMemo<SummaryStats>(() => {
    const total = localTasks.length;
    const doneColumnId = columns.find(c => c.id === 'done')?.id || columns[columns.length - 1]?.id;
    const completed = doneColumnId ? localTasks.filter(t => t.column === doneColumnId).length : 0;
    const percentComplete = total > 0 ? (completed / total) * 100 : 0;

    return { total, completed, percentComplete };
  }, [localTasks, columns]);

  const getTasksByColumn = useCallback((columnId: string) => {
    return localTasks.filter(t => t.column === columnId);
  }, [localTasks]);

  const handleMoveTask = useCallback((taskId: string, targetColumnId: string) => {
    setLocalTasks(prev => prev.map(t => 
      t.id === taskId ? { ...t, column: targetColumnId } : t
    ));
    onTaskUpdate({ action: 'move', taskId, data: { column: targetColumnId } });
  }, [onTaskUpdate]);

  const handleEditTask = useCallback((taskId: string, updates: Partial<Task>) => {
    setLocalTasks(prev => prev.map(t => 
      t.id === taskId ? { ...t, ...updates } : t
    ));
    onTaskUpdate({ action: 'edit', taskId, data: updates });
  }, [onTaskUpdate]);

  const handleCreateTask = useCallback((columnId: string, taskData: Omit<Task, 'id' | 'column'>) => {
    const newId = `task-${Date.now()}-${Math.floor(Math.random() * 1000)}`;
    const newTask: Task = {
      ...taskData,
      id: newId,
      column: columnId,
    };
    setLocalTasks(prev => [newTask, ...prev]);
    onTaskUpdate({ action: 'create', taskId: newId, data: newTask });
  }, [onTaskUpdate]);

  return {
    localTasks,
    stats,
    getTasksByColumn,
    handleMoveTask,
    handleEditTask,
    handleCreateTask,
  };
}


