// Path: /virtual/components/TaskCard.tsx
import React, { useState, useCallback } from 'react';
import {
  Card,
  Stack,
  Box,
  Badge,
  Avatar,
  Button,
  Text,
  Icon,
  Input,
  Spacer,
} from '@ggui-ai/design/primitives';
import { Dropdown } from '@ggui-ai/design/components';
import { TaskCardProps, Priority } from '/virtual/types';

export const TaskCard: React.FC<TaskCardProps> = ({
  task,
  allColumns,
  onMove,
  onEdit,
}) => {
  const [isEditing, setIsEditing] = useState(false);
  const [editedTitle, setEditedTitle] = useState(task.title);

  const handleSave = useCallback(() => {
    if (editedTitle.trim() !== '' && editedTitle !== task.title) {
      onEdit({ title: editedTitle });
    }
    setIsEditing(false);
  }, [editedTitle, task.title, onEdit]);

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') {
      handleSave();
    } else if (e.key === 'Escape') {
      setEditedTitle(task.title);
      setIsEditing(false);
    }
  };

  const priorityVariantMap: Record<Priority, 'success' | 'warning' | 'error'> = {
    low: 'success',
    medium: 'warning',
    high: 'error',
  };

  const moveOptions = allColumns
    .filter((col) => col.id !== task.column)
    .map((col) => ({
      value: col.id,
      label: col.name,
    }));

  return (
    <Card padding="var(--ggui-spacing-4)" shadow="sm" border radius="lg">
      <Stack gap="var(--ggui-spacing-4)">
        {/* Header Section */}
        {isEditing ? (
          <Input label="Edit task title" value={editedTitle} onChange={setEditedTitle} onBlur={handleSave} onKeyDown={handleKeyDown} autoFocus />
        ) : (
          <Stack direction="horizontal" justify="between" align="center" gap="var(--ggui-spacing-2)">
            <div onDoubleClick={() => setIsEditing(true)} style={{ flex: 1, cursor: 'pointer' }}>
              <Text variant="bodyLarge">
                {task.title}
              </Text>
            </div>
            <Spacer size="flex" />
            <Button
              variant="ghost"
              size="xs"
              onClick={() => setIsEditing(true)}
              aria-label="Edit title"
            >
              <Icon name="settings" size={14} />
            </Button>
          </Stack>
        )}

        {/* Metadata Section */}
        <Stack direction="horizontal" align="center" gap="var(--ggui-spacing-4)">
          <Badge variant={priorityVariantMap[task.priority]} size="sm">
            {task.priority.toUpperCase()}
          </Badge>
          {task.dueDate && (
            <Stack direction="horizontal" align="center" gap="var(--ggui-spacing-1)">
              <Icon name="settings" size={14} color="var(--ggui-color-onSurfaceVariant)" />
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                {task.dueDate}
              </Text>
            </Stack>
          )}
        </Stack>

        {/* Footer Section */}
        <Stack direction="horizontal" justify="between" align="center">
          <Avatar name={task.assignee} size="sm" />
          <Dropdown
            trigger={<Button variant="ghost" size="sm">Move</Button>}
            options={moveOptions}
            onChange={onMove}
            placement="bottom-end"
          />
        </Stack>
      </Stack>
    </Card>
  );
};

