// Path: /virtual/components/AddTaskForm.tsx
import React, { useState } from 'react';
import { Card, Stack, Button, Input, Select } from '@ggui-ai/design/primitives';
import { AddTaskFormProps, Priority } from '/virtual/types';

export const AddTaskForm: React.FC<AddTaskFormProps> = ({ onAdd, onCancel }) => {
  const [title, setTitle] = useState('');
  const [priority, setPriority] = useState<Priority>('medium');
  const [assignee, setAssignee] = useState('');
  const [dueDate, setDueDate] = useState('');

  const handleSubmit = () => {
    const trimmedTitle = title.trim();
    if (trimmedTitle === '') return;

    onAdd({
      title: trimmedTitle,
      priority,
      assignee: assignee.trim() || '',
      dueDate: dueDate || '',
    });
  };

  const priorityOptions = [
    { value: 'low', label: 'Low' },
    { value: 'medium', label: 'Medium' },
    { value: 'high', label: 'High' },
  ];

  return (
    <Card shadow="sm" radius="lg" border={true} padding={16}>
      <Stack gap={16}>
        <Input
          label="Task Title"
          value={title}
          onChange={setTitle}
          placeholder="What needs to be done?"
          autoFocus
        />

        <Select
          label="Priority"
          value={priority}
          onChange={(val) => setPriority(val as Priority)}
          options={priorityOptions}
        />

        <Input
          label="Assignee"
          value={assignee}
          onChange={setAssignee}
          placeholder="Who is responsible?"
        />

        <Input
          label="Due Date"
          type="date"
          value={dueDate}
          onChange={setDueDate}
        />

        <Stack direction="horizontal" gap={8} justify="end">
          <Button variant="ghost" onPress={onCancel}>
            Cancel
          </Button>
          <Button
            variant="primary"
            onPress={handleSubmit}
            disabled={title.trim() === ''}
          >
            Add Task
          </Button>
        </Stack>
      </Stack>
    </Card>
  );
};

