import React, { useState } from 'react';
import { Text } from '@ggui-ai/design/primitives';
import { ElementCellProps } from '/virtual/types';

/**
 * ElementCell represents a single element in the periodic table grid.
 * It handles grid positioning, visual states (selected/dimmed), and interaction.
 */
export const ElementCell: React.FC<ElementCellProps> = ({
  element,
  isSelected,
  isDimmed,
  onClick,
  colorToken,
}) => {
  const [isHovered, setIsHovered] = useState(false);

  const cellStyle: React.CSSProperties = {
    // Grid positioning from element data
    gridColumn: element.col,
    gridRow: element.row,

    // Visual presentation
    aspectRatio: '1/1',
    backgroundColor: colorToken,
    opacity: isDimmed ? 0.2 : 1,
    filter: isDimmed ? 'grayscale(100%)' : 'none',
    border: isSelected
      ? '2px solid var(--ggui-color-onSurface)'
      : '1px solid var(--ggui-color-outlineVariant)',
    borderRadius: 'var(--ggui-shape-radius-sm, 4px)',

    // Interactivity
    cursor: 'pointer',
    position: 'relative',
    padding: 'var(--ggui-spacing-1, 4px)',
    display: 'flex',
    flexDirection: 'column',
    alignItems: 'center',
    justifyContent: 'center',

    // Motion
    transition: 'transform 200ms ease-in-out, z-index 200ms, opacity 200ms',
    transform: isHovered ? 'scale(1.05)' : 'scale(1)',
    zIndex: isHovered || isSelected ? 10 : 1,
    boxSizing: 'border-box',
  };

  return (
    <div
      style={cellStyle}
      onClick={() => onClick(element)}
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
      onKeyDown={(e) => {
        if (e.key === 'Enter' || e.key === ' ') {
          e.preventDefault();
          onClick(element);
        }
      }}
      role="button"
      tabIndex={0}
      aria-label={`${element.name} - ${element.symbol}`}
    >
      {/* Atomic Number: Top-left corner */}
      <div style={{ position: 'absolute', top: '2px', left: '4px' }}>
        <Text variant="caption" size="xs">
          {element.atomicNumber}
        </Text>
      </div>

      {/* Symbol: Centered prominent text */}
      <Text variant="bodyLarge" weight="bold">
        {element.symbol}
      </Text>

      {/* Name: Bottom center with truncation */}
      <div style={{ position: 'absolute', bottom: '2px', left: 0, right: 0, textAlign: 'center', padding: '0 2px' }}>
        <Text variant="overline" truncate>
          {element.name}
        </Text>
      </div>
    </div>
  );
};

