  if (c.includes('alkali')) return 'warning';
  if (c.includes('nonmetal')) return 'success';
  if (c.includes('transition metal')) return 'primary';
  if (c.includes('halogen')) return 'error';
  if (c.includes('actinide') || c.includes('lanthanide')) return 'secondary';
