import React, { useState, useMemo, useRef, useEffect } from 'react';
  Container,
  Card,
  Stack,
  Box,
  Text,
  Heading,
  Button,
  Input,
  Badge,
  Avatar,
  Icon,
} from '@ggui-ai/design/primitives';
  ChatProps,
  ChatHookReturn,
  MessageGroup,
  ChatHeaderProps,
  MessageListProps,
  MessageBubbleProps,
  ChatInputProps,
} from '/virtual/types';

/**
 * useChat hook manages chat state, message grouping logic, and auto-scrolling behavior.
 */
export function useChat(props: ChatProps): ChatHookReturn {
  const [inputValue, setInputValue] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);

  // Transform flat messages array into groups based on sender to improve UI hierarchy
  const messageGroups = useMemo(() => {
    const groups: MessageGroup[] = [];
    props.messages.forEach((msg) => {
      const isCurrentUser = msg.sender === props.currentUser;
      const lastGroup = groups[groups.length - 1];

      if (lastGroup && lastGroup.sender === msg.sender) {
        lastGroup.messages.push(msg);
      } else {
        groups.push({
          sender: msg.sender,
          isCurrentUser,
          messages: [msg],
        });
      }
    });
    return groups;
  }, [props.messages, props.currentUser]);

  const handleSend = () => {
    const trimmedValue = inputValue.trim();
    if (!trimmedValue) return;

    props.onSend({
      text: trimmedValue,
      timestamp: new Date().toISOString(),
    });
    setInputValue('');
  };

  // Automatically scroll the message list to the bottom whenever new messages arrive
  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollIntoView({ behavior: 'smooth' });
    }
  }, [props.messages.length]);

  return {
    inputValue,
    setInputValue,
    messageGroups,
    handleSend,
    scrollRef,
  };
}

