import React from 'react';
import {
  Container, 
  Card, 
  Stack, 
  Box, 
  Divider, 
  Heading, 
  MotionKeyframes 
} from '@ggui-ai/design/primitives';

import { useComponent } from '/virtual/hooks';
import { StepProgress } from '/virtual/components/StepProgress';
import { ProfileForm } from '/virtual/components/ProfileForm';
import { PreferencesForm } from '/virtual/components/PreferencesForm';
import { ReviewSummary } from '/virtual/components/ReviewSummary';
