import type { OnboardingWizardProps } from '/virtual/types';

export function Component(props: OnboardingWizardProps) {
  const {
    currentStep,
    formData,
    isStepValid,
    handleUpdateField,
    nextStep,
    prevStep,
    submit
  } = useComponent({
    initialProfile: props.initialProfile,
    avatarOptions: props.avatarOptions,
    roleOptions: props.roleOptions,
    onComplete: props.onComplete
  });

  const getStepTitle = (step: number) => {
