export const WEATHER_ICONS = {
  Sunny: '☀️',
  Cloudy: '☁️',
  'Partly Cloudy': '⛅',
  Rainy: '🌧️',
  Showers: '🌦️',
  Stormy: '⛈️',
  Snowy: '❄️',
  Windy: '💨',
  default: '🌡️',
} as const;

export const UNITS = {
  CELSIUS: '°C',
  FAHRENHEIT: '°F',
  WIND_SPEED: 'km/h',
  HUMIDITY: '%',
} as const;

