// --- hooks.ts ---
// Path: /virtual/hooks.ts
import type { Props, HookReturn } from '/virtual/types';
import * as constants from '/virtual/constants';
// hooks.ts — state, handlers, data transformations
import { useState, useEffect, useMemo, useCallback, useRef } from 'react';

export function useComponent(props: Props): HookReturn {

  const weatherData = useMemo(() => {
    const isImperial = props.unit === 'imperial';
    const displayUnit = isImperial ? '°F' : '°C';

    const formattedTemperature = `${Math.round(props.temperature)}${displayUnit}`;
    const formattedHumidity = `${props.humidity}%`;
    const formattedWindSpeed = `${props.windSpeed}${isImperial ? ' mph' : ' km/h'}`;

    const condition = props.condition.toLowerCase();
    let conditionIcon = '⛅';

    if (condition === 'sunny' || condition === 'clear') {
      conditionIcon = '☀️';
    } else if (condition === 'cloudy' || condition === 'partly cloudy') {
      conditionIcon = '☁️';
    } else if (condition === 'rainy' || condition === 'showers') {
      conditionIcon = '🌧️';
    } else if (condition === 'snowy') {
      conditionIcon = '❄️';
    } else if (condition === 'stormy' || condition === 'thunderstorm') {
      conditionIcon = '⛈️';
    }

    return {
      formattedTemperature,
      formattedWindSpeed,
      formattedHumidity,
      conditionIcon,
      displayUnit
    };
  }, [props.temperature, props.unit, props.humidity, props.windSpeed, props.condition]);

  return weatherData;
}


