import { SurveyStep, SurveyData } from '/virtual/types';

export const STEPS: SurveyStep[] = [
  'identity',
  'satisfaction',
  'features',
  'comments',
  'review',
];

export const INITIAL_DATA: SurveyData = {
  name: '',
  email: '',
  satisfaction: null,
  features: [],
  comments: '',
};

export const STEP_TITLES: Record<SurveyStep, string> = {
  identity: 'Your Information',
  satisfaction: 'Overall Satisfaction',
  features: 'Feature Interests',
  comments: 'Additional Feedback',
