// --- hooks.ts ---
// Path: /virtual/hooks.ts
import type { Props, HookReturn } from '/virtual/types';
import * as constants from '/virtual/constants';
// hooks.ts — state, handlers, data transformations
import { useState, useMemo, useCallback, useEffect } from 'react';

const STEPS: SurveyStep[] = ['identity', 'satisfaction', 'features', 'comments', 'review'];

export function useComponent(props: Props): HookReturn {
  const [currentStep, setCurrentStep] = useState<SurveyStep>('identity');
  const [data, setData] = useState<SurveyData>({
    name: '',
    email: '',
    satisfaction: null,
    features: [],
    comments: '',
  });
  const [errors, setErrors] = useState<ValidationErrors>({});

  // Validation Logic: Runs whenever name or email changes
  useEffect(() => {
    const newErrors: ValidationErrors = {};

    // name: Must not be empty or only whitespace.
    if (data.name.length > 0 && !data.name.trim()) {
      newErrors.name = 'Name cannot be empty';
    }

    // email: Must match a standard email regex pattern.
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (data.email.length > 0 && !emailRegex.test(data.email)) {
      newErrors.email = 'Invalid email format';
    }

    setErrors(newErrors);
  }, [data.name, data.email]);

  const updateData = useCallback((updates: Partial<SurveyData>) => {
    setData((prev) => ({
      ...prev,
      ...updates,
    }));
  }, []);

  const stepIndex = useMemo(() => STEPS.indexOf(currentStep), [currentStep]);
  const totalSteps = STEPS.length;

  const isStepValid = useMemo(() => {
    switch (currentStep) {
      case 'identity':
        // Both name and email are non-empty and errors object is empty.
        return (
          data.name.trim().length > 0 &&
          data.email.trim().length > 0 &&
          Object.keys(errors).length === 0
        );
      case 'satisfaction':
        // satisfaction value is not null.
        return data.satisfaction !== null;
      case 'features':
        // Always true (optional).
        return true;
      case 'comments':
        // comments.length <= 500.
        return data.comments.length <= 500;
      case 'review':
        return true;
      default:
        return false;
    }
  }, [currentStep, data, errors]);

  const canGoBack = stepIndex > 0;
  const canGoNext = isStepValid && currentStep !== 'review';

  const handleNext = useCallback(() => {
    if (isStepValid && stepIndex < totalSteps - 1) {
      setCurrentStep(STEPS[stepIndex + 1]);
    }
  }, [isStepValid, stepIndex, totalSteps]);

  const handleBack = useCallback(() => {
    if (stepIndex > 0) {
      setCurrentStep(STEPS[stepIndex - 1]);
    }
  }, [stepIndex]);

  const submitSurvey = useCallback(() => {
    // Call props.onSubmit with the current state as per instruction 6
    props.onSubmit(data);
  }, [props, data]);

  return {
    currentStep,
    stepIndex,
    totalSteps,
    data,
    errors,
    isStepValid,
    canGoBack,
    canGoNext,
    handleNext,
    handleBack,
    updateData,
    submitSurvey,
  };
}


