// Path: /virtual/components/ProgressBar.tsx
import type { Props, HookReturn } from '/virtual/types';
import React from 'react';
import { Stack, Text, Progress } from '@ggui-ai/design/primitives';

export function MainView(props: ProgressBarProps) {
  const { stepIndex, totalSteps } = props;

  // Calculate the current step display number (1-indexed)
  const currentStepNumber = stepIndex + 1;

  // Calculate and clamp the progress percentage
  const progressPercentage = totalSteps > 0 
    ? Math.min(100, Math.max(0, (currentStepNumber / totalSteps) * 100))
    : 0;

  return (
    <Stack gap={2} style={{ width: '100%', marginBottom: 'var(--ggui-spacing-4, 16px)' }}>
      <Stack direction="horizontal" justify="between" align="center">
        <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
          Step {currentStepNumber} of {totalSteps}
        </Text>
      </Stack>
      <Progress value={progressPercentage} max={100} />
    </Stack>
  );
}


