// Path: /virtual/hooks.ts
import type { Props, HookReturn } from '/virtual/types';
import * as constants from '/virtual/constants';
// hooks.ts — state, handlers, data transformations
import { useState, useEffect, useMemo, useCallback, useRef } from 'react';

// ── Action Handlers (from actionsSpec) ──────────────────
//   props.actions: {"taskUpdate":{"label":"Task Updated","description":"Called when a task is moved, edited, or created. Payload: { action, taskId, data }","example":{"action":"move","taskId":"1","data":{"column":"in-progress"}}}}

export function useComponent(props: Props): HookReturn {
  const { tasks, columns, onTaskUpdate } = props;

  const [localTasks, setLocalTasks] = useState<Task[]>(tasks);

  useEffect(() => {
    setLocalTasks(tasks);
  }, [tasks]);

  const groupedTasks = useMemo(() => {
    const groups: Record<string, Task[]> = {};
    columns.forEach((col) => {
      groups[col.id] = [];
    });
    localTasks.forEach((task) => {
      if (groups[task.column]) {
        groups[task.column].push(task);
      }
    });
    return groups;
  }, [localTasks, columns]);

  const summary = useMemo(() => {
    const total = localTasks.length;
    const doneColumnId = columns.length > 0 ? columns[columns.length - 1].id : null;
    const completed = localTasks.filter((t) => t.column === doneColumnId).length;
    const percent = total === 0 ? 0 : Math.round((completed / total) * 100);
    return { total, completed, percent };
  }, [localTasks, columns]);

  const addTask = useCallback((columnId: string, taskData: Omit<Task, 'id' | 'column'>) => {
    const newId = Date.now().toString(36) + Math.random().toString(36).substring(2);
    const newTask: Task = {
      ...taskData,
      id: newId,
      column: columnId,
    };

    setLocalTasks((prev) => [...prev, newTask]);
    onTaskUpdate?.({
      action: 'create',
      taskId: newId,
      data: newTask,
    });
  }, [onTaskUpdate]);

  const moveTask = useCallback((taskId: string, targetColumnId: string) => {
    setLocalTasks((prev) =>
      prev.map((t) => (t.id === taskId ? { ...t, column: targetColumnId } : t))
    );
    onTaskUpdate?.({
      action: 'move',
      taskId,
      data: { column: targetColumnId },
    });
  }, [onTaskUpdate]);

  const updateTask = useCallback((taskId: string, updates: Partial<Task>) => {
    setLocalTasks((prev) => prev.map((t) => (t.id === taskId ? { ...t, ...updates } : t)));
    onTaskUpdate?.({
      action: 'edit',
      taskId,
      data: updates,
    });
  }, [onTaskUpdate]);

  return {
    localTasks,
    groupedTasks,
    summary,
    addTask,
    moveTask,
    updateTask,
  };
}


