import React, { useState, KeyboardEvent } from 'react';
import { 
  Card, 
  Stack, 
  Text, 
  Badge, 
  Avatar, 
  Input, 
  Icon 
} from '@ggui-ai/design/primitives';
import { Dropdown } from '@ggui-ai/design/components';
import { TaskCardProps } from '/virtual/types';

/**
 * TaskCard component represents an individual task in the Kanban board.
 * It provides title editing, priority display, and movement controls via a dropdown.
 */
export const TaskCard: React.FC<TaskCardProps> = ({ 
  task, 
  allColumns, 
  onMove, 
  onUpdate 
}) => {
  const [isEditing, setIsEditing] = useState(false);
  const [editValue, setEditValue] = useState(task.title);
  const [isHovered, setIsHovered] = useState(false);

  const handleTitleSubmit = () => {
    const trimmed = editValue.trim();
    if (trimmed && trimmed !== task.title) {
      onUpdate({ title: trimmed });
    } else {
      setEditValue(task.title);
    }
    setIsEditing(false);
  };

  const handleKeyDown = (e: KeyboardEvent<HTMLInputElement>) => {
    if (e.key === 'Enter') {
      handleTitleSubmit();
    } else if (e.key === 'Escape') {
      setEditValue(task.title);
      setIsEditing(false);
    }
  };

  const priorityVariantMap = {
    high: 'error',
    medium: 'warning',
    low: 'primary',
  } as const;

  const moveOptions = allColumns
    .filter((col) => col.id !== task.column)
    .map((col) => ({
      value: `move:${col.id}`,
      label: `Move to ${col.name}`,
      icon: <Icon name="chevron-right" size={14} />
    }));

  const dropdownOptions = [
    { value: 'edit', label: 'Edit', icon: <Icon name="settings" size={14} /> },
    ...moveOptions,
  ];

  const handleDropdownChange = (value: string) => {
    if (value === 'edit') {
      setIsEditing(true);
    } else if (value.startsWith('move:')) {
      const targetColumnId = value.split(':')[1];
      onMove(targetColumnId);
    }
  };

  return (
    <div
      onMouseEnter={() => setIsHovered(true)}
      onMouseLeave={() => setIsHovered(false)}
      style={{ 
        width: '100%',
        transition: 'all 200ms ease-in-out',
      }}
    >
      <Card
        padding={16}
        shadow={isHovered ? 'md' : 'sm'}
        border={true}
        radius="lg"
      >
        <Stack gap={8}>
          {/* Header Section: Title and Actions */}
          <Stack direction="horizontal" justify="between" align="center">
            <div style={{ flex: 1, minWidth: 0, marginRight: 'var(--ggui-spacing-2, 8px)' }}>
              {isEditing ? (
                <Input label="Task Title"
                  value={editValue}
                  onChange={setEditValue}
                  autoFocus
                  onBlur={handleTitleSubmit}
                  onKeyDown={handleKeyDown}
                  size="sm"
                />
              ) : (
                <div onDoubleClick={() => setIsEditing(true)}>
                  <Text variant="body" weight="medium" truncate>
                    {task.title}
                  </Text>
                </div>
              )}
            </div>
            <Dropdown
              trigger={
                <div style={{ padding: 'var(--ggui-spacing-1, 4px)', cursor: 'pointer' }}>
                  <Icon name="menu" size={16} color="var(--ggui-color-onSurfaceVariant, #52525b)" />
                </div>
              }
              options={dropdownOptions}
              onChange={handleDropdownChange}
              placement="bottom-end"
            />
          </Stack>

          {/* Metadata Section: Priority and Due Date */}
          <Stack direction="horizontal" justify="between" align="center">
            <Badge variant={priorityVariantMap[task.priority]} size="sm">
              {task.priority.charAt(0).toUpperCase() + task.priority.slice(1)}
            </Badge>

            {task.dueDate && (
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                {task.dueDate}
              </Text>
            )}
          </Stack>

          {/* Footer Section: Assignee */}
          <Stack direction="horizontal" align="center" gap={8}>
            <Avatar name={task.assignee} size="xs" />
            <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              {task.assignee}
            </Text>
          </Stack>
        </Stack>
      </Card>
    </div>
  );
};

