import type { Props, HookReturn } from '/virtual/types';
// components/index.tsx — main component composing sub-components
import React, { useState, useMemo, useCallback } from 'react';
import { Container, Stack, Box, Divider, Heading } from '@ggui-ai/design/primitives';

function useKanbanBoard(props: Props): HookReturn {
  const { tasks: initialTasks, columns, onTaskUpdate } = props;
  const [localTasks, setLocalTasks] = useState<Task[]>(initialTasks);

  const lastColumnId = useMemo(() => columns[columns.length - 1]?.id, [columns]);

  const groupedTasks = useMemo(() => {
    return localTasks.reduce((acc, task) => {
      if (!acc[task.column]) acc[task.column] = [];
      acc[task.column].push(task);
      return acc;
    }, {} as Record<string, Task[]>);
  }, [localTasks]);

  const summary = useMemo(() => {
    const total = localTasks.length;
    const completed = localTasks.filter(t => t.column === lastColumnId).length;
    const percent = total > 0 ? Math.round((completed / total) * 100) : 0;
    return { total, completed, percent };
  }, [localTasks, lastColumnId]);

  const addTask = useCallback((columnId: string, taskData: Omit<Task, 'id' | 'column'>) => {
    const newTask: Task = {
      ...taskData,
      id: `task-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`,
      column: columnId,
      priority: taskData.priority || 'low',
    };

    setLocalTasks(prev => [...prev, newTask]);
    onTaskUpdate?.({ action: 'create', taskId: newTask.id, data: newTask });
  }, [onTaskUpdate]);

  const moveTask = useCallback((taskId: string, targetColumnId: string) => {
    setLocalTasks(prev => prev.map(task => 
      task.id === taskId ? { ...task, column: targetColumnId } : task
    ));
    onTaskUpdate?.({ action: 'move', taskId, data: { column: targetColumnId } });
  }, [onTaskUpdate]);

  const updateTask = useCallback((taskId: string, updates: Partial<Task>) => {
    setLocalTasks(prev => prev.map(task => 
      task.id === taskId ? { ...task, ...updates } : task
    ));
    onTaskUpdate?.({ action: 'edit', taskId, data: updates });
  }, [onTaskUpdate]);

  return {
    localTasks,
    groupedTasks,
    summary,
    addTask,
    moveTask,
    updateTask
  };
}

export function MainView(props: Props) {
  const { columns } = props;
  const { groupedTasks, summary, addTask, moveTask, updateTask } = useKanbanBoard(props);

  return (
    <Box background="var(--ggui-color-surface, #fafafa)" padding="var(--ggui-spacing-6, 24px)">
      <Container maxWidth="full">
        <Stack gap={24}>
          <Stack gap={8}>
            <Heading level={2}>Project Roadmap</Heading>
            <BoardSummary {...summary} />
          </Stack>

          <Divider margin={0} />

          <Box style={{ overflowX: 'auto', paddingBottom: 'var(--ggui-spacing-4, 16px)' }}>
            <Stack direction="horizontal" gap={16} align="start">
              {columns.map(column => (
                <KanbanColumn
                  key={column.id}
                  column={column}
                  tasks={groupedTasks[column.id] || []}
                  allColumns={columns}
                  onAddTask={(task) => addTask(column.id, task)}
                  onMoveTask={moveTask}
                  onUpdateTask={updateTask}
                />
              ))}
            </Stack>
          </Box>
        </Stack>
      </Container>
    </Box>
  );
}


