// --- hooks.ts ---
// Path: /virtual/hooks.ts
import type { Props, HookReturn } from '/virtual/types';
import * as constants from '/virtual/constants';
// hooks.ts — state, handlers, data transformations
import { useState, useEffect, useMemo, useCallback, useRef } from 'react';

// ── Action Handlers (from actionsSpec) ──────────────────
//   props.actions: {"sendMessage":{"label":"Send Message","description":"Called when user sends a message. Payload: { text, timestamp }","example":{"text":"Sounds good!","timestamp":"2026-03-15T14:10:00Z"}}}

export function useComponent(props: Props): HookReturn {

  const [inputValue, setInputValue] = useState('');
  const scrollRef = useRef<HTMLDivElement>(null);

  const processedMessages = useMemo(() => {
    return props.messages.map((msg, index) => {
      const isOwnMessage = msg.sender === props.currentUser;
      const showSenderName = index === 0 || props.messages[index - 1].sender !== msg.sender;
      const showTimestamp = index === props.messages.length - 1 || props.messages[index + 1].sender !== msg.sender;

      return {
        ...msg,
        id: `${index}-${msg.timestamp}`,
        isOwnMessage,
        showSenderName,
        showTimestamp,
      };
    });
  }, [props.messages, props.currentUser]);

  useEffect(() => {
    if (scrollRef.current) {
      scrollRef.current.scrollTop = scrollRef.current.scrollHeight;
    }
  }, [props.messages.length]);

  const handleSend = useCallback(() => {
    const trimmedValue = inputValue.trim();
    if (trimmedValue) {
      props.onSend({
        text: trimmedValue,
        timestamp: new Date().toISOString(),
      });
      setInputValue('');
    }
  }, [inputValue, props]);

  const canSend = inputValue.trim().length > 0;

  return {
    inputValue,
    processedMessages,
    scrollRef,
    setInputValue,
    handleSend,
    canSend,
  };
}


