import React from 'react';
import { Stack, Box, Text } from '@ggui-ai/design/primitives';
import { MessageBubbleProps } from '/virtual/types';

/**
 * MessageBubble component renders an individual chat message.
 * It adapts its alignment and styling based on whether the message was sent by the current user.
 */
export const MessageBubble: React.FC<MessageBubbleProps> = ({ message }) => {
  const {
    isOwnMessage,
    showSenderName,
    showTimestamp,
    text,
    sender,
    timestamp,
  } = message;

  // Format the timestamp for display (e.g., 10:30 AM)
  const formattedTime = React.useMemo(() => {
    try {
      const date = new Date(timestamp);
      if (isNaN(date.getTime())) return timestamp;
      return date.toLocaleTimeString([], {
        hour: '2-digit',
        minute: '2-digit',
      });
    } catch (e) {
      return timestamp;
    }
  }, [timestamp]);

  return (
    <Stack
      align={isOwnMessage ? 'end' : 'start'}
      gap={4}
      style={{ width: '100%' }}
    >
      {/* Sender name for received messages */}
      {showSenderName && (
        <Text
          variant="caption"
          color="var(--ggui-color-onSurfaceVariant, #52525b)"
          style={{ marginBottom: 'var(--ggui-spacing-1, 4px)' }}
        >
          {sender}
        </Text>
      )}

      {/* Message bubble */}
      <Box
        padding="var(--ggui-spacing-2, 8px) var(--ggui-spacing-4, 16px)"
        background={
          isOwnMessage
            ? 'var(--ggui-color-primary-600, #0284c7)'
            : 'var(--ggui-color-surfaceVariant, #f4f4f5)'
        }
        borderRadius={
          isOwnMessage ? '12px 12px 2px 12px' : '12px 12px 12px 2px'
        }
        style={{
          maxWidth: '80%',
          wordBreak: 'break-word',
        }}
      >
        <Text
          variant="body"
          color={
            isOwnMessage
              ? 'var(--ggui-color-onPrimary, #ffffff)'
              : 'var(--ggui-color-onSurface, #18181b)'
          }
          style={{ whiteSpace: 'pre-wrap' }}
        >
          {text}
        </Text>
      </Box>

      {/* Message timestamp */}
      {showTimestamp && (
        <Text
          variant="caption"
          color="var(--ggui-color-onSurfaceVariant, #52525b)"
          style={{ marginTop: 'var(--ggui-spacing-1, 4px)' }}
        >
          {formattedTime}
        </Text>
      )}
    </Stack>
  );
};

