} from '/virtual/types';

/**
 * Hook to process raw stock data into formatted display data.
 */
function useStockTicker(stocks: Stock[], lastUpdated?: string): UseStockTickerReturn {
  const formattedStocks: FormattedStock[] = stocks.map((stock) => {
    const isPositive = stock.change >= 0;
    return {
      ...stock,
      priceFormatted: `$${stock.price.toFixed(2)}`,
      changeFormatted: `${isPositive ? '+' : ''}${stock.change.toFixed(2)}`,
      changePercentFormatted: `${stock.changePercent.toFixed(2)}%`,
      isPositive,
      trendIcon: isPositive ? '▲' : '▼',
    };
  });

  const formattedTimestamp = lastUpdated 
    ? new Date(lastUpdated).toLocaleTimeString() 
    : 'Just now';

  return {
    formattedStocks,
    formattedTimestamp,
  };
}

/**
 * Header component for the Dashboard.
