            Last updated: {lastUpdated}
          </Text>
        </Stack>
        <Divider margin={0} />
      </Stack>
    </Box>
  );
}

/**
 * Individual Stock Card component.
 */
function StockCard({ stock }: StockCardProps) {
  const accentColor = stock.isPositive 
    ? 'var(--ggui-color-success)' 
    : 'var(--ggui-color-error)';

  return (
    <Card 
      shadow="sm" 
