import { ProfileData } from '/virtual/types';

export const TOTAL_STEPS = 3;

export const STEPS = {
  PROFILE: 1,
  PREFERENCES: 2,
  REVIEW: 3,
} as const;

export const STEP_TITLES: Record<number, string> = {
  [STEPS.PROFILE]: 'Profile Setup',
  [STEPS.PREFERENCES]: 'Preferences',
  [STEPS.REVIEW]: 'Review & Confirm',
};

export const ROLE_OPTIONS = ['Developer', 'Designer', 'Manager', 'Other'];

export const DEFAULT_AVATARS = ['👤', '🐱', '🦊', '🐨'];

export const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

export const DEFAULT_PROFILE_DATA: ProfileData = {
  name: '',
  email: '',
  avatar: DEFAULT_AVATARS[0],
  role: 'Developer',
  emailNotifications: true,
  theme: 'light',
};

// --- hooks.ts ---
// Path: /virtual/hooks.ts
import type { Props, HookReturn } from '/virtual/types';
import * as constants from '/virtual/constants';
// hooks.ts — state, handlers, data transformations
import { useState, useMemo, useCallback } from 'react';

// ── Action Handlers (from actionsSpec) ──────────────────
//   props.actions: {"complete":{"label":"Complete Setup","description":"Called with all profile data when user completes onboarding","example":{"name":"Jane","email":"jane@example.com","avatar":"🧑‍💻","role":"Developer","emailNotifications":true,"theme":"dark"}}}

export function useComponent(props: Props): HookReturn {
  const [formData, setFormData] = useState<ProfileData>(() => ({
    name: '',
    email: '',
    avatar: props.avatarOptions?.[0] || '',
    role: '',
    emailNotifications: true,
    theme: 'light',
    ...props.initialProfile,
  }));

  const [currentStep, setCurrentStep] = useState(1);

  const isStepValid = useMemo(() => {
    if (currentStep === 1) {
      const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
      return formData.name.trim() !== '' && emailRegex.test(formData.email);
    }
    if (currentStep === 2) {
      return formData.role !== '';
    }
    return true;
  }, [currentStep, formData.name, formData.email, formData.role]);

  const updateField = useCallback((updates: Partial<ProfileData>) => {
    setFormData((prev) => ({ ...prev, ...updates }));
  }, []);

  const nextStep = useCallback(() => {
    setCurrentStep((prev) => (prev < 3 ? prev + 1 : prev));
  }, []);

  const prevStep = useCallback(() => {
    setCurrentStep((prev) => (prev > 1 ? prev - 1 : prev));
  }, []);

  const handleSubmit = useCallback(() => {
    props.onComplete(formData);
  }, [props.onComplete, formData]);

  return {
    currentStep,
    formData,
    isStepValid,
    nextStep,
    prevStep,
    updateField,
    handleSubmit,
  };
}


