export function MainView(props: Props & HookReturn) {
  const { formData, updateField, roleOptions } = props;

  return (
    <Container>
      <Stack gap={6}>
        <Box>
          <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
            These settings help us personalize your experience. You can always change them later in your profile settings.
          </Text>
        </Box>

        <Stack gap={4}>
          <FormField
            label="Your Role"
            description="Choose the role that best describes your daily work."
          >
            <Select
              value={formData.role}
              onChange={(value) => updateField({ role: value })}
              options={(roleOptions || []).map((role) => ({
                value: role,
                label: role,
              }))}
              placeholder="Select your role"
            />
          </FormField>

          <Divider margin="var(--ggui-spacing-4)" />

          <Row justify="between" align="center">
            <Stack gap={1}>
              <Text variant="label">Email Notifications</Text>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                Receive updates about your account activity
              </Text>
            </Stack>
            <Toggle
              checked={formData.emailNotifications}
              onChange={(checked) => updateField({ emailNotifications: checked })}
            />
          </Row>

          <Row justify="between" align="center">
            <Stack gap={1}>
              <Text variant="label">Dark Mode</Text>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                Switch between light and dark interface themes
              </Text>
            </Stack>
            <Toggle
              checked={formData.theme === 'dark'}
              onChange={(checked) => updateField({ theme: checked ? 'dark' : 'light' })}
            />
          </Row>
        </Stack>
      </Stack>
    </Container>
  );
}


