import type { Props, HookReturn } from '/virtual/types';
// components/index.tsx — main component composing sub-components
import React from 'react';
import { Container, Card, Stack, Row, Box, Divider, Spacer, Text, Heading, Button, Input, TextArea, Select, Checkbox, Toggle, RadioGroup, Slider, Badge, Spinner, Avatar, Alert, Progress, Image, Icon, Link, Tooltip, Table, Tabs, Toast, Accordion } from '@ggui-ai/design/primitives';
import { SearchField, FormField, MenuItem, Tag, Dropdown, Autocomplete, Breadcrumb, Pagination } from '@ggui-ai/design/components';

export function MainView(props: NavigationProps) {
  const { currentStep, isNextDisabled, onBack, onNext, onComplete } = props;

  return (
    <Row
      justify="between"
      align="center"
      style={{ marginTop: 'var(--ggui-spacing-8)', width: '100%' }}
    >
      {currentStep > 1 ? (
        <Button variant="outline" onClick={onBack}>
          Back
        </Button>
      ) : (
        <Box />
      )}

      {currentStep < 3 ? (
        <Button
          variant="primary"
          disabled={isNextDisabled}
          onClick={onNext}
        >
          Next
        </Button>
      ) : (
        <Button
          variant="primary"
          onClick={onComplete}
        >
          Complete Setup
        </Button>
      )}
    </Row>
  );
}


// --- index.tsx ---
// Path: /virtual/components/index.tsx
import React, { useState, useMemo } from 'react';
import {
  Container, Card, Stack, Box, Divider, Text, Heading,
  Button, Input, Select, Toggle, RadioGroup, Badge,
  Avatar, Progress, MotionKeyframes
} from '@ggui-ai/design/primitives';
import {
  OnboardingProps as Props, 
  ProfileData,
  StepIndicatorProps,
  StepProfileProps,
  StepPreferencesProps,
  StepReviewProps,
  NavigationProps
} from '/virtual/types';

/**
 * Sub-component for the top progress section
 */
function StepIndicator({ currentStep, totalSteps }: StepIndicatorProps) {
  const titles = [
    "Create Your Profile",
    "Account Preferences",
    "Review Your Profile"
  ];

  return (
    <Stack gap={12}>
      <Progress
        value={(currentStep / totalSteps) * 100}
        size="sm"
        variant="default"
      />
      <Heading level={2} color="var(--ggui-color-onSurface, #18181b)">
        {titles[currentStep - 1]}
      </Heading>
    </Stack>
  );
}

/**
 * Step 1: Profile Information
 */
function StepProfile({ data, avatarOptions, onChange }: StepProfileProps) {
  return (
    <Stack gap={24}>
      <Input label="Full Name"
        required
        helperText="How should we address you in the app?"
        value={data.name}
        onChange={(val) => onChange({ name: val })}
        placeholder="e.g. Alex Rivera"
      />

      <Input label="Email Address"
        required
        type="email"
        helperText="We'll use this for account recovery and updates."
        value={data.email}
        onChange={(val) => onChange({ email: val })}
        placeholder="alex@example.com"
      />

      <Stack gap={12}>
        <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
          Choose an Avatar
        </Text>
        <Stack direction="horizontal" gap={12} wrap>
          {avatarOptions.map((url) => (
            <div
              key={url}
              onClick={() => onChange({ avatar: url })}
              style={{
                cursor: 'pointer',
                padding: 'var(--ggui-spacing-1, 4px)',
                borderRadius: 'var(--ggui-shape-radius-full, 9999px)',
                border: data.avatar === url
                  ? '2px solid var(--ggui-color-primary-600, #0284c7)'
                  : '2px solid transparent'
              }}
            >
              <Avatar src={url} size="lg" name={data.name || 'User'} />
            </div>
          ))}
        </Stack>
      </Stack>
    </Stack>
  );
}

/**
 * Step 2: User Preferences
 */
function StepPreferences({ data, roleOptions, onChange }: StepPreferencesProps) {
  return (
    <Stack gap={24}>
      <Select label="Your Primary Role"
        helperText="Help us tailor the content to your professional needs."
        value={data.role}
        options={roleOptions.map(role => ({ value: role, label: role }))}
        onChange={(val) => onChange({ role: val })}
      />

      <Stack gap={12}>
        <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
          App Customization
        </Text>
        <Card border padding={16} radius="lg">
          <Stack direction="horizontal" justify="between" align="center">
            <Stack gap={2}>
              <Text variant="body" weight="medium" color="var(--ggui-color-onSurface, #18181b)">Email Notifications</Text>
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                Stay updated on platform activity
              </Text>
            </Stack>
            <Toggle
              checked={data.emailNotifications}
              onChange={(val) => onChange({ emailNotifications: val })}
            />
          </Stack>
        </Card>

        <Stack gap={8}>
          <RadioGroup 
            label="Interface Theme"
            direction="horizontal"
            value={data.theme}
            onChange={(val) => onChange({ theme: val as 'light' | 'dark' })}
            options={[
              { value: 'light', label: 'Light Mode' },
              { value: 'dark', label: 'Dark Mode' }
            ]}
          />
        </Stack>
      </Stack>
    </Stack>
  );
}

/**
 * Step 3: Summary Review
 */
function StepReview({ data }: StepReviewProps) {
  return (
    <Stack gap={24}>
      <Box padding={20} background="var(--ggui-color-surfaceVariant, #f4f4f5)" borderRadius="var(--ggui-shape-radius-lg, 12px)">
        <Stack direction="horizontal" gap={20} align="center">
          <Avatar src={data.avatar} size="xl" name={data.name} />
          <Stack gap={4}>
            <Heading level={3} color="var(--ggui-color-onSurface, #18181b)">{data.name}</Heading>
            <Text color="var(--ggui-color-onSurfaceVariant, #52525b)">{data.email}</Text>
          </Stack>
        </Stack>
      </Box>

      <Stack gap={16}>
        <Stack direction="horizontal" justify="between">
          <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Professional Role</Text>
          <Badge variant="primary">{data.role}</Badge>
        </Stack>
        <Divider margin={0} />
        <Stack direction="horizontal" justify="between">
          <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Notification Status</Text>
          <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)">{data.emailNotifications ? 'Enabled' : 'Disabled'}</Text>
        </Stack>
        <Divider margin={0} />
        <Stack direction="horizontal" justify="between">
          <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">Default Theme</Text>
          <Text variant="bodySmall" color="var(--ggui-color-onSurface, #18181b)" style={{ textTransform: 'capitalize' }}>{data.theme}</Text>
        </Stack>
      </Stack>
    </Stack>
  );
}

/**
 * Navigation Controls
 */
function Navigation({ currentStep, isNextDisabled, onBack, onNext, onComplete }: NavigationProps) {
  return (
    <Stack direction="horizontal" justify="between" align="center">
      <Button 
        variant="ghost" 
        onClick={onBack} 
        disabled={currentStep === 1}
      >
        Back
      </Button>
      {currentStep < 3 ? (
        <Button 
          variant="primary" 
          onClick={onNext} 
          disabled={isNextDisabled}
        >
          Continue
        </Button>
      ) : (
        <Button 
          variant="primary" 
          onClick={onComplete}
        >
          Complete Onboarding
        </Button>
      )}
    </Stack>
  );
}

export function Component(props: Props) {
  const [currentStep, setCurrentStep] = useState(1);
  const [formData, setFormData] = useState<ProfileData>({
    name: '',
    email: '',
    avatar: props.avatarOptions[0] || '',
    role: props.roleOptions[0] || '',
    emailNotifications: true,
    theme: 'light',
    ...props.initialProfile
  });

  const updateField = (updates: Partial<ProfileData>) => {
    setFormData(prev => ({ ...prev, ...updates }));
  };

  const isStepValid = useMemo(() => {
    if (currentStep === 1) {
      const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
      return formData.name.trim().length > 0 && emailRegex.test(formData.email);
    }
    return true;
  }, [currentStep, formData]);

  const nextStep = () => setCurrentStep(s => Math.min(s + 1, 3));
  const prevStep = () => setCurrentStep(s => Math.max(s - 1, 1));
  const handleSubmit = () => props.onComplete(formData);

  return (
    <Container maxWidth="sm" padding={24}>
      <MotionKeyframes />
      <Card shadow="md" radius="xl" padding={32}>
        <Stack gap={32}>
          <StepIndicator currentStep={currentStep} totalSteps={3} />

          <div key={currentStep} style={{ animation: 'ggui-fadeIn 300ms ease-out', minHeight: '340px' }}>
            {currentStep === 1 && (
              <StepProfile 
                data={formData} 
                avatarOptions={props.avatarOptions} 
                onChange={updateField} 
              />
            )}
            {currentStep === 2 && (
              <StepPreferences 
                data={formData} 
                roleOptions={props.roleOptions} 
                onChange={updateField} 
              />
            )}
            {currentStep === 3 && (
              <StepReview data={formData} />
            )}
          </div>

          <Divider margin={0} />

          <Navigation 
            currentStep={currentStep}
            isNextDisabled={!isStepValid}
            onBack={prevStep}
            onNext={nextStep}
            onComplete={handleSubmit}
          />
        </Stack>
      </Card>
    </Container>
  );
}


